import{b as t,J as r,g as e,j as o}from"./chunks/framework.DVAsBjJ_.js";const g=JSON.parse('{"title":"일반 문서 관리","description":"","frontmatter":{},"headers":[],"relativePath":"document/index.md","filePath":"document/index.md","lastUpdated":1780890704000}'),l={name:"document/index.md"};function i(n,a,s,h,d,u){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="일반-문서-관리" tabindex="-1">일반 문서 관리 <a class="header-anchor" href="#일반-문서-관리" aria-label="Permalink to &quot;일반 문서 관리&quot;">​</a></h1><p>프로젝트와 관련된 각종 공문, 지침, 업무 자료 등 일반적인 문서들을 분류별로 저장하고 구성원들과 공유하는 문서 관리 페이지입니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 문서 관리 &gt; 일반 문서 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>프로젝트 진행 과정에서 발생하는 다양한 형식의 문서(파일, 웹 링크)를 체계적으로 관리합니다. 카테고리별 탭 분류를 통해 원하는 문서를 신속하게 찾을 수 있으며, 문서별 조회수 확인 및 중요 문서 스크랩 기능을 통해 업무 효율을 높입니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li><strong>카테고리 탭 분류</strong>: 문서의 성격에 따라 정의된 카테고리별로 문서를 분리하여 조회 가능</li><li><strong>다중 파일 첨부</strong>: 개별 파일에 대한 설명과 함께 여러 개의 파일을 동시에 업로드 지원</li><li><strong>참조 링크 등록</strong>: 관련 웹사이트나 온라인 자료를 링크 형태로 등록하여 연결</li><li><strong>문서 스크랩</strong>: 사용자별로 중요한 문서를 별도로 보관할 수 있는 스크랩 기능 제공</li><li><strong>상세 조회수 추적</strong>: 문서 본문뿐만 아니라 첨부 파일 및 링크별 개별 클릭 횟수(조회수) 관리</li><li><strong>권한 기반 제어</strong>: 프로젝트별 쓰기 권한에 따른 문서 작성 및 수정 제한</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-목록-및-검색-제어" tabindex="-1">1. 목록 및 검색 제어 <a class="header-anchor" href="#_1-목록-및-검색-제어" aria-label="Permalink to &quot;1. 목록 및 검색 제어&quot;">​</a></h3><p>문서를 검색하고 분류별로 필터링하는 영역입니다.</p><ul><li><strong>필터 컨트롤</strong>: 프로젝트 선택, 페이지당 표시 건수, 정렬 순서(최신순 등), 검색어 입력</li><li><strong>카테고리 탭</strong>: 등록된 카테고리 항목이 탭 형태로 표시되며, 클릭 시 해당 분류의 문서만 필터링됩니다.</li></ul><h3 id="_2-문서-목록" tabindex="-1">2. 문서 목록 <a class="header-anchor" href="#_2-문서-목록" aria-label="Permalink to &quot;2. 문서 목록&quot;">​</a></h3><p>문서의 제목, 작성자, 작성일, 조회수 등을 일람표 형태로 표시합니다.</p><ul><li><strong>문서 정보</strong>: 카테고리, 제목(파일/링크 아이콘 포함), 작성자, 작성일, 조회수</li><li><strong>페이징</strong>: 하단 페이지네이션을 통해 전체 문서를 탐색할 수 있습니다.</li></ul><h3 id="_3-상세-보기-및-관리" tabindex="-1">3. 상세 보기 및 관리 <a class="header-anchor" href="#_3-상세-보기-및-관리" aria-label="Permalink to &quot;3. 상세 보기 및 관리&quot;">​</a></h3><p>문서의 본문 내용을 확인하고 첨부된 자원을 관리하는 화면입니다.</p><ul><li><strong>본문 내용</strong>: 등록된 문서의 상세 내용 및 서식 적용 텍스트 표시</li><li><strong>첨부 자원</strong>: 첨부된 파일 리스트(다운로드 가능) 및 참조 링크 리스트 표시</li><li><strong>스크랩 및 조회수</strong>: 문서 하단의 스크랩 버튼으로 개인 보관함에 추가할 수 있으며, 실시간 조회수가 반영됩니다.</li></ul><h3 id="_4-문서-작성-및-수정" tabindex="-1">4. 문서 작성 및 수정 <a class="header-anchor" href="#_4-문서-작성-및-수정" aria-label="Permalink to &quot;4. 문서 작성 및 수정&quot;">​</a></h3><p>문서를 신규로 등록하거나 기존 내용을 변경하는 화면입니다.</p><ul><li><strong>기본 정보</strong>: 카테고리 선택, 문서 제목 및 본문 작성</li><li><strong>파일/링크 추가</strong>: 새 파일을 추가하거나 기존 파일을 변경/삭제할 수 있으며, 각 파일별 설명을 덧붙일 수 있습니다. 참조 링크 역시 다수 등록 가능합니다.</li></ul><h2 id="💡-주요-관리-포인트" tabindex="-1">💡 주요 관리 포인트 <a class="header-anchor" href="#💡-주요-관리-포인트" aria-label="Permalink to &quot;💡 주요 관리 포인트&quot;">​</a></h2><h3 id="파일-및-링크의-개별-조회수" tabindex="-1">파일 및 링크의 개별 조회수 <a class="header-anchor" href="#파일-및-링크의-개별-조회수" aria-label="Permalink to &quot;파일 및 링크의 개별 조회수&quot;">​</a></h3><p>시스템은 문서 자체의 조회수 외에도 <strong>첨부 파일 다운로드 횟수</strong>와 <strong>링크 클릭 횟수</strong>를 별도로 기록합니다. 이를 통해 구성원들이 어떤 자료를 가장 많이 참조하는지 파악할 수 있습니다.</p><h3 id="문서-스크랩-활용" tabindex="-1">문서 스크랩 활용 <a class="header-anchor" href="#문서-스크랩-활용" aria-label="Permalink to &quot;문서 스크랩 활용&quot;">​</a></h3><p>중요도가 높거나 자주 참조해야 하는 문서는 상세 보기 화면에서 [스크랩] 아이콘을 클릭하여 개인 계정에 보관할 수 있습니다. 스크랩된 문서는 별도의 개인 메뉴에서 모아볼 수 있습니다.</p><h3 id="효율적인-파일-관리" tabindex="-1">효율적인 파일 관리 <a class="header-anchor" href="#효율적인-파일-관리" aria-label="Permalink to &quot;효율적인 파일 관리&quot;">​</a></h3><p>문서 수정 시 기존 첨부 파일을 유지하면서 새로운 파일을 추가하거나, 특정 파일만 교체할 수 있습니다. 파일 업로드 시 파일명을 수정하지 않아도 &#39;파일 설명&#39; 필드를 통해 문서 내에서 해당 파일의 용도를 명확히 기술할 수 있습니다.</p>',27)])])}const p=t(l,[["render",i]]);export{g as __pageData,p as default};
